Set.Payload:
{
  "jsonrpc": "2.0",
  "id": {mcp.id},
  "result": {
    "tools": 

      [
        {
          "description": "Retrieves a simple JSON string list of ingredients for the requested food by calling Vertex AI's Gemini 1.5 Flash model.",
          "inputSchema": {
            "properties": {
              "food": {
                "examples": [
                  "chocolate chip cookies"
                ],
                "type": "string"
              }
            },
            "type": "object"
          },
          "name": "getIngredients",
          "outputSchema": {
            "properties": {
              "ingredients": {
                "items": {
                  "type": "string"
                },
                "type": "array"
              }
            },
            "type": "object"
          },
          "title": "Get ingredients for a food item"
        }
      ]

  }
}
